# BFS on the side-reflection group of a right triangle with positive
# unequal rational legs, in exact rational arithmetic. By the
# universality theorem the choice of legs (a, b) with a != b is
# immaterial; we use (a, b) = (1, 2).
from fractions import Fraction
def A_2D_universal(d_max=20):
    O, I = Fraction(0), Fraction(1)
    V = [(O, O), (I, O), (O, I + I)]
    sides = [(0, 1), (1, 2), (2, 0)]
    def reflection(p0, p1):
        dx, dy = p1[0] - p0[0], p1[1] - p0[1]
        L = dx*dx + dy*dy
        a = (dx*dx - dy*dy) / L
        b = 2*dx*dy / L
        d = -a
        tx = (1 - a)*p0[0] - b*p0[1]
        ty = -b*p0[0] + (1 - d)*p0[1]
        return (a, b, b, d, tx, ty)
    def compose(M, N):
        a1, b1, c1, d1, tx1, ty1 = M
        a2, b2, c2, d2, tx2, ty2 = N
        return (a1*a2 + b1*c2, a1*b2 + b1*d2,
                c1*a2 + d1*c2, c1*b2 + d1*d2,
                a1*tx2 + b1*ty2 + tx1,
                c1*tx2 + d1*ty2 + ty1)
    gens = [reflection(V[i], V[j]) for i, j in sides]
    identity = (I, O, O, I, O, O)
    seen = {identity}; frontier = {identity}; seq = [1]
    for _ in range(d_max):
        new = set()
        for M in frontier:
            for g in gens:
                N = compose(g, M)
                if N not in seen:
                    new.add(N); seen.add(N)
        seq.append(len(new)); frontier = new
    return seq

